mapper.update:
update seat
seat_code = #{seatCode}, area_id = #{areaId}, hour_price = #{hourPrice}, seat_image = #{seatImage}, seat_description = #{seatDescription}, status = #{status}, has_socket = #{hasSocket}, has_window = #{hasWindow}, update_time = #{updateTime}, update_user = #{updateUser},
where id = #{id}

mapper.select:
select s.id, s.seat_code, s.area_id, a.name as area_name, coalesce(s.hour_price, 0) as hour_price, s.seat_image as image, s.seat_description, s.status, s.has_socket, s.has_window, s.create_time, s.update_time from seat s left join area a on s.area_id = a.id
and s.seat_code like concat('%', #{seatCode}, '%')
and s.area_id = #{areaId}
and s.status = #{status}
order by s.create_time desc

select count(s.id) from seat s


        and s.seat_code like concat('%', #{seatCode}, '%')


        and s.area_id = #{areaId}


        and s.status = #{status}

select id, seat_id, status, start_time, end_time
from orders
where seat_id = #{seatId}
  and status in (1, 2, 3)
  and start_time < #{endTime}
  and end_time > #{startTime}
